// src/replication/pluginRegistry.ts
import { ReplicationPlugin, DOEnv, InternalSqliteDB } from './types';
import { postgresReplicator } from './postgresReplicator';

const plugins: ReplicationPlugin[] = [
    postgresReplicator,
];

export class ReplicationPluginRegistry {
    private plugins: Map<string, ReplicationPlugin>;

    constructor() {
        this.plugins = new Map();
        plugins.forEach(plugin => this.plugins.set(plugin.name, plugin));
    }

    async runAll(env: DOEnv, internalDb: InternalSqliteDB, tables: string[]): Promise<void> {
        for (const plugin of this.plugins.values()) {
            console.log(`Running replication plugin: ${plugin.name}`);
            try {
                await plugin.replicate(env, internalDb, tables);
                console.log(`Replication plugin ${plugin.name} completed successfully.`);
            } catch (error) {
                console.error(`Replication plugin ${plugin.name} failed:`, error);
            }
        }
    }

    getPlugin(name: string): ReplicationPlugin | undefined {
        return this.plugins.get(name);
    }
}
