// src/replication/postgresReplicator.ts
import { ReplicationPlugin, DOEnv, InternalSqliteDB } from './types';

export const postgresReplicator: ReplicationPlugin = {
    name: 'supabase-postgres',
    async replicate(env: DOEnv, internalDb: InternalSqliteDB, tables: string[]): Promise<void> {
        const { SUPABASE_URL, SUPABASE_ANON_KEY } = env;

        if (!SUPABASE_URL || !SUPABASE_ANON_KEY) {
            console.warn('Supabase URL or Anon Key not configured. Skipping Postgres replication.');
            return;
        }

        const headers = {
            'apikey': SUPABASE_ANON_KEY,
            'Authorization': `Bearer ${SUPABASE_ANON_KEY}`,
            'Content-Type': 'application/json',
            'Accept': 'application/json',
        };

        for (const tableName of tables) {
            console.log(`Replicating table: ${tableName}`);
            try {
                const response = await fetch(`${SUPABASE_URL}/rest/v1/${tableName}?select=*`, { headers });

                if (!response.ok) {
                    throw new Error(`Failed to fetch data from Supabase for table ${tableName}: ${response.statusText}`);
                }

                const data: any[] = await response.json();
                console.log(`Fetched ${data.length} rows from ${tableName}`);

                if (data.length === 0) {
                    console.log(`No data to replicate for table ${tableName}.`);
                    continue;
                }

                const firstRow = data[0];
                const columns = Object.keys(firstRow).map(col => `"${col}" TEXT`).join(', ');
                const createTableSql = `CREATE TABLE IF NOT EXISTS "${tableName}" (${columns});`;
                await internalDb.exec(createTableSql);

                await internalDb.exec(`DELETE FROM "${tableName}";`);

                const insertColumns = Object.keys(firstRow).map(col => `"${col}"`).join(', ');
                const valuePlaceholders = Object.keys(firstRow).map(() => '?').join(', ');
                const insertSql = `INSERT INTO "${tableName}" (${insertColumns}) VALUES (${valuePlaceholders});`;

                for (const row of data) {
                    const values = Object.values(row);
                    await internalDb.run(insertSql, values);
                }
                console.log(`Successfully replicated ${data.length} rows into internal SQLite for table ${tableName}.`);

            } catch (error) {
                console.error(`Error replicating table ${tableName}:`, error);
                throw error;
            }
        }
    },
};
